UPDATE public.courses SET detail_content = '{"longDescription":"In questo corso per adolescenti imparerai le basi di Python, uno dei linguaggi di programmazione più versatili e richiesti nel mondo del lavoro. Creerai applicazioni come chatbot e programmi interattivi. Acquisirai esperienza pratica con strumenti e tecniche standard, imparando anche a sviluppare e pubblicare i tuoi progetti.","age":"13+ anni","level":"Principiante","duration":"32 lezioni","tags":["Python","Programmazione","Logica","Progetti pratici"],"topics":["Fondamenti del linguaggio Python","Variabili, funzioni e strutture dati","Programmazione orientata agli oggetti","Creazione di progetti interattivi","Introduzione al debugging e testing"],"projectExamples":[{"title":"Chatbot Discord"},{"title":"Applicazione interattiva"},{"title":"Gioco testuale"}],"modules":[{"title":"Modulo 1: Introduzione a Python","lessons":["1. Installazione e configurazione dell''ambiente di sviluppo.","2. Primi passi: variabili e tipi di dati.","3. Input/Output e interazione con l''utente.","4. Operatori e espressioni."],"result":"Comprensione delle basi di Python e creazione dei primi programmi."},{"title":"Modulo 2: Strutture di controllo","lessons":["5. Istruzioni condizionali if/else.","6. Cicli for e iterazione.","7. Cicli while e controllo del flusso.","8. Esercitazione pratica con problemi logici."],"result":"Padronanza delle strutture di controllo fondamentali."},{"title":"Modulo 3: Funzioni e modularità","lessons":["9. Definizione e chiamata di funzioni.","10. Parametri e valori di ritorno.","11. Scope delle variabili e best practices.","12. Creazione di un mini-progetto con funzioni."],"result":"Capacità di organizzare il codice in modo modulare."},{"title":"Modulo 4: Strutture dati","lessons":["13. Liste e operazioni su liste.","14. Dizionari e tuple.","15. Comprensione delle liste.","16. Progetto con strutture dati."],"result":"Utilizzo efficace delle strutture dati Python."},{"title":"Modulo 5: File e gestione degli errori","lessons":["17. Lettura e scrittura di file.","18. Gestione delle eccezioni.","19. Debugging e risoluzione problemi.","20. Progetto con persistenza dati."],"result":"Gestione professionale di file ed errori."},{"title":"Modulo 6: Introduzione alla OOP","lessons":["21. Classi e oggetti.","22. Metodi e attributi.","23. Ereditarietà base.","24. Progetto con classi."],"result":"Comprensione dei fondamenti della programmazione orientata agli oggetti."},{"title":"Modulo 7: Librerie e moduli","lessons":["25. Importazione e utilizzo di moduli.","26. Librerie standard utili.","27. Installazione di pacchetti esterni.","28. Creazione di un progetto con librerie."],"result":"Utilizzo dell''ecosistema Python per estendere le funzionalità."},{"title":"Modulo 8: Progetto finale","lessons":["29. Pianificazione del progetto finale.","30. Sviluppo del progetto.","31. Testing e debugging finale.","32. Presentazione del progetto."],"result":"Completamento di un progetto Python completo e funzionante."}]}'::jsonb WHERE slug = 'python-base' AND (detail_content IS NULL OR detail_content = '{}'::jsonb);

UPDATE public.courses SET detail_content = '{"longDescription":"In questo corso per adolescenti libererai la tua creatività e scoprirai le potenzialità avanzate del linguaggio Python! Creerai applicazioni avanzate come chatbot, siti web e programmi basati sull''intelligenza artificiale. Acquisirai non solo esperienza pratica con strumenti e tecniche standard, ma imparerai anche a sviluppare e pubblicare i tuoi progetti open source. Le competenze acquisite ti permetteranno di fare un passo importante nel mondo della tecnologia!","age":"13+ anni","level":"Avanzato","duration":"32 lezioni","tags":["API","HTML","Estrazione dati","Intelligenza artificiale"],"topics":["Programmazione back-end","Introduzione allo sviluppo web","Padronanza dell''intelligenza artificiale","Integrazione dell''AI in applicazioni già pronte","Funzioni avanzate di Python come lambda, gestione file ed eccezioni","Sviluppo di bot, siti e AI usando Python, API, framework web e librerie ML"],"projectExamples":[{"title":"Bot Discord avanzato"},{"title":"Sito web con Flask"},{"title":"Progetto AI con Machine Learning"}],"modules":[{"title":"Modulo 1: Bot Discord che non si ferma mai","lessons":["1. Gli strumenti dei veri programmatori!","2. Gli strumenti dei veri programmatori! VsCode","3. Importiamo la nostra prima libreria!","4. Il bot risponde già alle nostre richieste!"],"result":"Creazione di un bot Discord funzionante con le basi di Python e Git."},{"title":"Modulo 2: File, cartelle e sviluppo web","lessons":["5. File e cartelle","6. Applicare la nostra conoscenza","7. Introduzione allo sviluppo web.","8. HTML e CSS"],"result":"Comprensione della struttura dei file e introduzione al web development."},{"title":"Modulo 3: Flask e back-end","lessons":["9. Flask. Configurazione dell''ambiente.","10. Modelli e strumenti di template","11. Imparare i percorsi web e come non perdere le pagine web.","12. Una lezione segreta! Cambiare le pagine dinamicamente."],"result":"Creazione di siti web dinamici con Flask."},{"title":"Modulo 4: Database e Portfolio","lessons":["13. Database. Il Diario del programmatore","14. Autorizzazione degli utenti.","15. Distribuzione del progetto. Preparazione del portfolio.","16. Creazione di un sito web Portfolio"],"result":"Creazione e deployment di un sito web portfolio completo."},{"title":"Modulo 5: Intelligenza Artificiale e Machine Learning","lessons":["17. Comprendere l''IA e l''apprendimento automatico.","18. I dati sono la chiave del successo. Estrazione di dati da fonti aperte.","19. Le basi del Natural Language Processing. La libreria NLTK. I generatori di liste di Python.","20. Visione computerizzata? Che cos''è?"],"result":"Comprensione dei fondamenti dell''AI e del machine learning."},{"title":"Modulo 6: Modelli AI e pratica","lessons":["21. Imparare una nuova libreria! Usare i modelli addestrati con il codice!","22. Battaglia di AI! Organizzare una competizione, discutere e testare.","23. Imparare nuove librerie e fissare obiettivi!","24. Mettiamo in pratica la nostra conoscenza!"],"result":"Utilizzo pratico di modelli AI pre-addestrati."},{"title":"Modulo 7: Integrazione AI nei progetti","lessons":["25. Configurazione dell''IDE per il progetto precedentemente creato.","26. Inferenza del modello addestrato nel bot Discord.","27. Creare un traduttore vocale!","28. Aggiungere un pulsante e implementare la logica!"],"result":"Integrazione di AI in applicazioni esistenti."},{"title":"Modulo 8: Hackathon - Progetto finale","lessons":["29. Spiegazione di ciò che vogliamo ottenere. Analisi.","30. Elaborazione di una soluzione.","31. Testare, eseguire il debug e risolvere.","32. Dimostrazione della soluzione."],"result":"Partecipazione a un hackathon con progetto finale completo."}]}'::jsonb WHERE slug = 'python-ai' AND (detail_content IS NULL OR detail_content = '{}'::jsonb);
